import { AxiosError, AxiosResponse } from 'axios';
import { call, put } from 'redux-saga/effects';

import api from '../../services/api';
import {
  BlockCardCallback,
  BlockCardResponse,
  blockCardActions,
} from '../ducks/blockCard';
import { CardsResponseData } from '../ducks/customers/cards';
import { getCardData } from './_utils/getCardData';

export function* blockCardRequest({
  lastFourNumbers,
  blockCode,
  callBack,
}: {
  lastFourNumbers: string;
  blockCode: string;
  callBack?: BlockCardCallback;
}) {
  try {
    const selectedCardObj: CardsResponseData['data']['Cards'][0] = yield call(
      getCardData,
      lastFourNumbers
    );

    const response: AxiosResponse<BlockCardResponse> = yield call(
      api.put,
      `/cards/block`,
      {
        encryptedCardNumber: selectedCardObj.CartaoCriptografado,
        blockCode,
      },
    );

    if (callBack) {
      yield call(callBack, { statusCode: response.status });
    }

    yield put(blockCardActions.blockCardSuccess(response.data));
  } catch (error) {
    const { response } = error as AxiosError<BlockCardResponse>;
    const responseData = response?.data;

    yield put(blockCardActions.blockCardFailed(responseData));
  }
}

function* blockCardClear() {
  yield call(blockCardActions.blockCardClear);
}

