import { AxiosResponse } from 'axios';
import { call, put, select } from 'redux-saga/effects';

import api from '../../../services/api';
import {
  automaticDebtActions,
  AutomaticDebtResponse,
} from '../../ducks/dacc/automaticDebt';
import { getCustomerCpf } from '../customers/functions';

interface SituationRaceResponse {
  timeout: boolean;
  call: AxiosResponse<AutomaticDebtResponse>;
}

export function* getAutoDebtSituation() {
  try {
    const cpf: string = yield select(getCustomerCpf);

    if (!cpf) throw new Error('Insufficient information!');

    const { data }: AxiosResponse<AutomaticDebtResponse> = yield call(
      api.get,
      `/debito-automatico/${cpf}`,
    );

    const isActive = !!(
      data?.data?.bankNumber && data?.data?.checkingAccountNumber
    );

    yield put(automaticDebtActions.automaticDebtSuccess({ ...data, isActive }));
  } catch (error) {
    yield put(automaticDebtActions.automaticDebtClean());
  }
}

