import { AxiosError, AxiosResponse } from 'axios';
import { call, put, putResolve, select } from 'redux-saga/effects';

import api from '../../services/api';
import { cardsActions } from '../ducks/customers/cards';
import {
  DuplicateCardResponse,
  duplicateCardActions,
} from '../ducks/duplicateCard';
import { AppReducers } from '../reducers/Models';
import { getCardsReducer } from './_utils/getCardData';

export function* duplicateCardRequest({
  data: {
    lastFourNumbers,
    accountNumber,
    isVirtual,
    organizationNumber,
    onSuccess,
    reasonBlockCode,
    onFailed,
  },
}: {
  data: {
    lastFourNumbers: string;
    accountNumber: string;
    isVirtual: boolean;
    organizationNumber: number;
    type: string;
    reasonBlockCode?: string;
    onSuccess?: () => void;
    onFailed?: () => void;
  };
}) {
  try {
    yield putResolve(cardsActions.cardRequest(() => {}));

    const cardsReducer: AppReducers['cardsReducer'] = yield select(
      getCardsReducer,
    );

    const encryptedCardNumber = cardsReducer.data?.Cards.find(card =>
      card.NrCartao.endsWith(lastFourNumbers),
    )?.CartaoCriptografado;
    if (!encryptedCardNumber) throw new Error('Encrypted Card Not Found!');


    const response: AxiosResponse<DuplicateCardResponse> = yield call(
      api.post,
      `/cards/duplicate-card`,
      {
        encryptedCardNumber,
        accountNumber,
        isVirtual,
        organizationNumber,
        ...(reasonBlockCode && { reasonBlockCode }),
      },
    );
    if (onSuccess) {
      yield call(onSuccess);
    }
    yield put(duplicateCardActions.duplicateCardSuccess(response?.data));
  } catch (error) {
    const { response } = error as AxiosError<DuplicateCardResponse>;
    const responseData = response?.data;
    if (onFailed) {
      yield call(onFailed);
    }
    yield put(duplicateCardActions.duplicateCardFailed(responseData));
  }
}

function* duplicateCardClear() {
  yield call(duplicateCardActions.duplicateCardClear);
}

