import { api } from '@semparar/mf-app-user';
import { call, delay, put, race, select } from 'redux-saga/effects';

import { exemptionEligibilityActions } from '../../ducks/exemptionEligibility';
import { AppReducers } from '../../reducers/Models';

const getFeaturesState = (state: AppReducers) => state.featuresReducer;

export function* getExemptionEligibility() {
  try {
    const featuresState: AppReducers['featuresReducer'] = yield select(
      getFeaturesState,
    );

    const hideBenefitMonthlyFeeExemption =
      Reflect.get(featuresState, 'hideBenefitMonthlyFeeExemption') ?? false;

    if (hideBenefitMonthlyFeeExemption) {
      throw new Error('isEligible is not a boolean');
    }

    const { response } = yield race({
      response: call(api.post, '/fintech/v1/fee/checkFeeExemptionEligibility'),
    });

    if (
      Reflect.has(response.data, 'isEligible') &&
      typeof response.data.isEligible === 'boolean'
    ) {
      yield put(
        exemptionEligibilityActions.successExemptionEligibility(response.data),
      );
    } else {
      throw new Error('isEligible is not a boolean');
    }
  } catch (error) {
    yield put(exemptionEligibilityActions.failedExemptionEligibility());
  }
}

