import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
import { AccountTypes } from '@semparar/mf-app-user';

import { InvoiceObj, InvoiceResponse } from '../../../ducks/invoice';
import { ProductsReducerData } from '../../../ducks/products';

export interface TransactionResume {
  title: string;
  icon: PropsIconsNameCore | null;
  id: string;
  value: string;
  fullValue: string;
  description: string;
  isInternational: boolean;
  date: string;
  formattedDate: string;
  isOnUsTransaction: boolean;
  captureType: string | null;
  exchangeRate: string | null;
  dollarTransactionValue: string | null;
  onPress?: () => void;
  lastInvoiceValue?: number;
}

export interface ShortTypes {
  CartaoCredito: InvoiceResponse['data']['CartaoCredito'];
  Compras: InvoiceResponse['data']['CartaoCredito'][0]['Compras'];
  card: ProductsReducerData[0]['Cartoes'][0];
  getFormatted: {
    allCards: ShortTypes['CartaoCredito'];
    account: typeof AccountTypes;
    cards: ProductsReducerData;
    lastFourAccountNumber: string;
    date: string;
    invoice?: InvoiceResponse['data'];
  };
}

export interface FunctionsType {
  getFormattedCards: ({
    allCards,
    account,
    cards,
    lastFourAccountNumber,
    date,
  }: ShortTypes['getFormatted']) => InvoiceObj[];
  getFormattedAccounts: ({
    allCards,
    account,
    cards,
    lastFourAccountNumber,
    date,
    invoice,
  }: ShortTypes['getFormatted']) => InvoiceObj[];
  getTransactionItems: ({
    Compras,
    onlyCardNumbers,
  }: {
    Compras: ShortTypes['Compras'];
    onlyCardNumbers: string;
  }) => InvoiceObj['items'];
  getUnifiedTransactions: (
    data: ShortTypes['CartaoCredito'],
  ) => ShortTypes['CartaoCredito'];
}

