   221→        ?.reduce((acc, purchaseObj) => acc + purchaseObj.ValorTransacao, 0)
   222→        .toFixed(2),
   223→      description: capitalizeEachWord(description),
   224→      date,
   225→      items: getTransactionItems({
   226→        Compras,
   227→        onlyCardNumbers,
   228→      }),
   229→    };
   230→  });
