   242→};
   243→
   244→const getDescription = ({
   245→  isSticker,
   246→  cardNameSplited,
   247→  cardName,
   248→}: {
   249→  isSticker: boolean;
   250→  cardNameSplited: string[];
   251→  cardName: string;
   252→}) => {
   253→  if (isSticker) return ' ';
   254→  return cardNameSplited?.length > 2
   255→    ? `${cardNameSplited?.[0]} ${cardNameSplited?.[1]}`
   256→    : cardName;
   257→};
   258→
   259→const getDollarTransactionValue = (
   260→  dollarTransactionValue: number | undefined | null,
   261→  code: string | undefined | null,
   262→): string | null => {
   263→  if (!code || code === 'USD' || !dollarTransactionValue) {
   264→    return null;
   265→  }
   266→  return formatToNumericCurrency(
   267→    dollarTransactionValue,
   268→    getDecimalPlacesBasedOnValue(dollarTransactionValue),
   269→  );
   270→};
   271→
   272→const getValue = (value: number | undefined | null): string | null => {
   273→  if (!value) {
   274→    return null;
   275→  }
   276→  return `R$ ${formatToNumericCurrency(
   277→    value,
   278→    getDecimalPlacesBasedOnValue(value),
   279→  )}`;
   280→};
   281→
   282→const getDecimalPlacesBasedOnValue = (value: number) => {
   283→  value = Math.abs(value);
   284→  let decimalPlaces = 2;
   285→  if (value <= 0.001) {
   286→    decimalPlaces = 4;
   287→  } else if (value <= 0.01) {
   288→    decimalPlaces = 3;
   289→  }
   290→  return decimalPlaces;
   291→};
   292→
   293→const getTransactionItems: FunctionsType['getTransactionItems'] = ({
   294→  Compras,
   295→  onlyCardNumbers,
   296→}) => {
   297→  return getFilteredUndefinedTypes(Compras)?.reduce((acc, transaction) => {
   298→    const transactionDate = moment(transaction.Data).format('dddd DD MMMM');
   299→    const formattedDate = moment(transaction.Data).format('DD/MM/YYYY');
   300→    const dateIndex = transaction.Data
   301→      ? acc[transactionDate]?.findIndex(
   302→          transactionObj => transactionObj.date === transactionDate,
   303→        )
   304→      : undefined;
   305→
   306→    const captureTypeFormatted =
   307→      captureType?.[transaction.FormaDeCaptura as CAPTURE_TYPE_NUMBER_TYPE] ??
   308→      null;
   309→
   310→    const onUsTransaction =
   311→      transactionsIds?.[
   312→        transaction.CodigoTransacao as TRANSACTIONS_NUMBER_TYPE
   313→      ];
   314→
   315→    const description = getDescriptionTransaction(transaction);
   316→
   317→    const transactionFormatted: TransactionResume &
   318→      Partial<InvoiceDetailsResponseData['data']> = {
   319→      ...onUsTransaction,
   320→      title:
   321→        !onUsTransaction?.showOriginalDescription && onUsTransaction?.title
   322→          ? onUsTransaction?.title
   323→          : removeExtraSpaces(capitalizeEachWord(transaction.Descricao)),
   324→      icon: (onUsTransaction?.icon as PropsIconsNameCore) ?? 'icon-money',
   325→      id: `${onlyCardNumbers}-${transaction.Sequencia}`,
   326→      value: ` ${getValue(transaction.ValorTransacao)}`,
   327→      fullValue: `${transaction.ValorTransacao}`,
   328→      description,
   329→      isInternational: transaction?.Moeda !== 'BRL',
   330→      date: transactionDate,
   331→      formattedDate,
   332→      isOnUsTransaction: !!onUsTransaction,
   333→      captureType: captureTypeFormatted,
   334→      exchangeRate: transaction?.TaxaConversaoDolar
   335→        ? formatToNumericCurrency(transaction?.TaxaConversaoDolar)
   336→        : null,
   337→      dollarTransactionValue: getDollarTransactionValue(
   338→        transaction?.ValorTransacaoDolar,
   339→        transaction?.CodigoMoedaOrigem,
   340→      ),
   341→      onPress: () => {
