   347→      },
   348→    };
   349→
   350→    if (transaction?.Estabelecimento) {
   351→      transactionFormatted.usePoint = { name: transaction?.Estabelecimento };
   352→    }
   353→
   354→    if (transaction?.Veiculo && transaction.Veiculo?.Placa) {
   355→      transactionFormatted.item = { plate: transaction.Veiculo?.Placa };
   356→    }
   357→
   358→    if (typeof dateIndex !== 'undefined' && dateIndex >= 0) {
   359→      acc[transactionDate].push(transactionFormatted);
   360→      return acc;
   361→    }
   362→
   363→    return { ...acc, [transactionDate]: [transactionFormatted] };
   364→  }, {} as InvoiceObj['items']);
   365→};
   366→
   367→const getDescriptionTransaction = (transaction: ShortTypes['Compras'][0]) => {
   368→  if (transaction?.Moeda !== 'BRL')
   369→    return `${transaction?.Moeda} ${formatToNumericCurrency(
   370→      transaction.ValorOriginalTransacao,
   371→      getDecimalPlacesBasedOnValue(transaction.ValorOriginalTransacao),
   372→    )}`;
   373→  return transaction.TotalParcelas > 1
   374→    ? `Parcela ${transaction.Parcela}/${transaction.TotalParcelas}`
   375→    : 'À vista';
