   435→      year,
   436→      isTAG: false,
   437→      invoiceNumber: undefined,
   438→      dueDate: dueDate.toDate(),
   439→    };
   440→
   441→    if (typeof invoices[year] !== 'undefined') {
   442→      invoices[year].push(invoice);
   443→      return;
   444→    }
   445→    invoices[year] = [invoice];
   446→  });
   447→
   448→  tagInvoices?.billSummaryList.forEach(bill => {
   449→    const invoiceNumber = bill?.billNumberTokenized;
   450→    const billDate = moment(bill?.dueDateOfBill);
   451→    const year = billDate.year();
   452→
   453→    const month = billDate.format('MMMM');
   454→    const day = billDate.date();
   455→    const invoice: PreviousInvoice = {
   456→      year,
   457→      month,
   458→      day,
   459→      isTAG: true,
   460→      invoiceNumber,
   461→      dueDate: billDate.toDate(),
   462→    };
   463→
   464→    const hasInvoice = invoices?.[year]?.some(
   465→      SPInvoice => SPInvoice.month === month,
