import { propsItems as CardClosedInvoicePropsItems } from '@semparar/design-system-app/src/atomic/fintech/CardClosedInvoice/Models/index';
import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
import { AccountTypes } from '@semparar/mf-app-user';
import { navigate } from '~/routes/navigation';

import { PreviousInvoice } from '../../../screens/InvoicesHistory/Models';
import { moment } from '../../../services/moment';
import {
  capitalizeEachWord,
  formatToCurrency,
  formatToNumericCurrency,
  removeExtraSpaces,
} from '../../../utils/functions';
import transactionsIds, {
  CAPTURE_TYPE_NUMBER_TYPE,
  TRANSACTIONS_NUMBER_TYPE,
  captureType,
} from '../../../utils/transactions';
import {
  FiservBlockTypes,
  State as ProductsTypes,
} from '../../ducks/customers/products';
import { InvoiceObj } from '../../ducks/invoice';
import {
  InvoicesFintechProps,
  InvoicesFintechResponse,
} from '../../ducks/invoices';
import { InvoicesListFintechResponse } from '../../ducks/invoicesList';
import { AppReducers } from '../../reducers/Models';
import { InvoiceDetailsResponseData } from './details';
import { FunctionsType, ShortTypes, TransactionResume } from './Models/invoice';

export const getAccount = ({
  accountReducer,
}: {
  accountReducer: typeof AccountTypes;
}) => accountReducer;

export const getCards = ({
  productsReducer,
}: {
  productsReducer: ProductsTypes;
}) => productsReducer.data;

export const getSituation = (
  currentInvoice: InvoicesFintechResponse['data']['invoices'][0],
  allInvoices: InvoicesFintechResponse['data']['invoices'],
  blockCode: FiservBlockTypes | undefined,
  currentDate: moment.Moment = moment(),
): CardClosedInvoicePropsItems['type'] => {
  if (currentInvoice.Situacao === 'Fechada') {
    const hasNextClosedInvoice = allInvoices?.find(
      invoice =>
        invoice.Situacao === 'Fechada' &&
        moment(invoice.Vencimento).isAfter(moment(currentInvoice.Vencimento)),
    );

    if (
      blockCode !== FiservBlockTypes.WAITING_PAYMENT &&
      currentInvoice.Pagamento === 'Não Pago' &&
      currentInvoice.ValorPgtoMinimo > currentInvoice.ValorPago &&
      currentInvoice.ValorPago > 0 &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      !hasNextClosedInvoice
    ) {
      return 'late';
    }

    if (
      blockCode !== FiservBlockTypes.WAITING_PAYMENT &&
      currentInvoice.Pagamento === 'Não Pago' &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      !hasNextClosedInvoice
    ) {
      return 'delayed';
    }

    if (
      (blockCode === FiservBlockTypes.WAITING_PAYMENT &&
        currentDate.month() === moment(currentInvoice.Vencimento).month()) ||
      (currentInvoice.Pagamento === 'Não Pago' &&
        !currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')))
    ) {
      return 'closed';
    }

    if (
      currentInvoice.Pagamento === 'Não Pago' &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      hasNextClosedInvoice
    ) {
      return 'unidentifiedPayment';
    }

    if (
      currentInvoice.Pagamento === 'Pago Integral' &&
      currentInvoice.Valor === currentInvoice.ValorPago
    ) {
      return 'paid';
    }
    if (currentInvoice.status === 'Atrasada') {
      return 'late';
    }

    if (
      currentInvoice.Pagamento === 'Pago Parcial' &&
      currentInvoice.ValorPgtoMinimo <= currentInvoice.ValorPago
    ) {
      return 'paidMessage';
    }

    return 'paid';
  }
  if (currentInvoice.Situacao === 'Em Aberto') {
    return 'default';
  }
};

export const getFormattedAccounts: FunctionsType['getFormattedAccounts'] = ({
  allCards,
  lastFourAccountNumber,
  date,
  invoice,
}) => {
  const filteredAccounts: ShortTypes['CartaoCredito'] = allCards.filter(item =>
    item?.Cartao?.endsWith(lastFourAccountNumber),
  );
  return getUnifiedTransactions(filteredAccounts)?.map(
    ({ Cartao, Compras }) => {
      const lastInvoiceDate = moment(invoice?.DataVencimento)
        .subtract(1, 'M')
        .format('MMMM');
      Compras?.push({
        Sequencia: Compras?.length + 1,
        Data: '',
        Descricao: `Fatura de ${lastInvoiceDate}`,
        Parcela: 0,
        TotalParcelas: 0,
        ValorOriginalTransacao: 0,
        ValorTransacao: invoice?.ValorFaturaAnterior ?? 0,
        Tipo: 'D',
        Moeda: 'BRL',
        CodigoTransacao: 0,
        FormaDeCaptura: null,
        NumeroReferencia: '-',
        TaxaConversao: 0,
      });
      const items = getTransactionItems({
        Compras,
        onlyCardNumbers: Cartao,
      });
      return {
        title: 'Outros Lançamentos',
        type: 'others',
        value: formatToCurrency(
          getFilteredUndefinedTypes(Compras)
            ?.reduce((acc, purchaseObj) => acc + purchaseObj.ValorTransacao, 0)
            .toFixed(2),
        ),
        fullValue: getFilteredUndefinedTypes(Compras)
          ?.reduce((acc, purchaseObj) => acc + purchaseObj.ValorTransacao, 0)
          .toFixed(2),
        date,
        description: ' ',
        items,
      };
    },
  );
};

export const getFormattedCards: FunctionsType['getFormattedCards'] = ({
  allCards,
  account,
  cards,
  lastFourAccountNumber,
  date,
}) => {
  const filteredCards = allCards.filter(
    item => !item?.Cartao?.endsWith(lastFourAccountNumber),
  );
  return getUnifiedTransactions(filteredCards)?.map(({ Cartao, Compras }) => {
    const onlyCardNumbers = getReplacedCreditCard(Cartao);
    const creditCardAccount = account.card?.cardNumber;
    const lastFour = creditCardAccount?.slice(-4);

    const isSticker = lastFour === onlyCardNumbers;

    let card: ShortTypes['card'] | undefined;
    cards?.some(item => {
      return item?.Cartoes?.some(cardItem => {
        if (cardItem?.NrCartao?.endsWith(onlyCardNumbers)) {
          card = cardItem;
          return true;
        }
        return false;
      });
    });

    const cardName = card?.NomePortador ?? ' ';
    const cardNameSplited = cardName?.split(' ');

    const title = isSticker
      ? 'Tag Sem Parar'
      : `Cartão final ${onlyCardNumbers}`;
    const type = getType({ isSticker, card });
    const description = getDescription({
      isSticker,
      cardNameSplited,
      cardName,
    });

    return {
      title,
      type,
      value: formatToCurrency(
        getFilteredUndefinedTypes(Compras)
          ?.reduce((acc, purchaseObj) => acc + purchaseObj.ValorTransacao, 0)
          .toFixed(2),
      ),
      fullValue: getFilteredUndefinedTypes(Compras)
        ?.reduce((acc, purchaseObj) => acc + purchaseObj.ValorTransacao, 0)
        .toFixed(2),
      description: capitalizeEachWord(description),
      date,
      items: getTransactionItems({
        Compras,
        onlyCardNumbers,
      }),
    };
  });
};

const getType = ({
  isSticker,
  card,
}: {
  isSticker: boolean;
  card: ShortTypes['card'] | undefined;
}) => {
  if (isSticker) return 'tag';
  return card?.Virtual ? 'virtualCard' : 'physicalCard';
};

const getDescription = ({
  isSticker,
  cardNameSplited,
  cardName,
}: {
  isSticker: boolean;
  cardNameSplited: string[];
  cardName: string;
}) => {
  if (isSticker) return ' ';
  return cardNameSplited?.length > 2
    ? `${cardNameSplited?.[0]} ${cardNameSplited?.[1]}`
    : cardName;
};

const getDollarTransactionValue = (
  dollarTransactionValue: number | undefined | null,
  code: string | undefined | null,
): string | null => {
  if (!code || code === 'USD' || !dollarTransactionValue) {
    return null;
  }
  return formatToNumericCurrency(
    dollarTransactionValue,
    getDecimalPlacesBasedOnValue(dollarTransactionValue),
  );
};

const getValue = (value: number | undefined | null): string | null => {
  if (!value) {
    return null;
  }
  return `R$ ${formatToNumericCurrency(
    value,
    getDecimalPlacesBasedOnValue(value),
  )}`;
};

const getDecimalPlacesBasedOnValue = (value: number) => {
  value = Math.abs(value);
  let decimalPlaces = 2;
  if (value <= 0.001) {
    decimalPlaces = 4;
  } else if (value <= 0.01) {
    decimalPlaces = 3;
  }
  return decimalPlaces;
};

const getTransactionItems: FunctionsType['getTransactionItems'] = ({
  Compras,
  onlyCardNumbers,
}) => {
  return getFilteredUndefinedTypes(Compras)?.reduce((acc, transaction) => {
    const transactionDate = moment(transaction.Data).format('dddd DD MMMM');
    const formattedDate = moment(transaction.Data).format('DD/MM/YYYY');
    const dateIndex = transaction.Data
      ? acc[transactionDate]?.findIndex(
          transactionObj => transactionObj.date === transactionDate,
        )
      : undefined;

    const captureTypeFormatted =
      captureType?.[transaction.FormaDeCaptura as CAPTURE_TYPE_NUMBER_TYPE] ??
      null;

    const onUsTransaction =
      transactionsIds?.[
        transaction.CodigoTransacao as TRANSACTIONS_NUMBER_TYPE
      ];

    const description = getDescriptionTransaction(transaction);

    const transactionFormatted: TransactionResume &
      Partial<InvoiceDetailsResponseData['data']> = {
      ...onUsTransaction,
      title:
        !onUsTransaction?.showOriginalDescription && onUsTransaction?.title
          ? onUsTransaction?.title
          : removeExtraSpaces(capitalizeEachWord(transaction.Descricao)),
      icon: (onUsTransaction?.icon as PropsIconsNameCore) ?? 'icon-money',
      id: `${onlyCardNumbers}-${transaction.Sequencia}`,
      value: ` ${getValue(transaction.ValorTransacao)}`,
      fullValue: `${transaction.ValorTransacao}`,
      description,
      isInternational: transaction?.Moeda !== 'BRL',
      date: transactionDate,
      formattedDate,
      isOnUsTransaction: !!onUsTransaction,
      captureType: captureTypeFormatted,
      exchangeRate: transaction?.TaxaConversaoDolar
        ? formatToNumericCurrency(transaction?.TaxaConversaoDolar)
        : null,
      dollarTransactionValue: getDollarTransactionValue(
        transaction?.ValorTransacaoDolar,
        transaction?.CodigoMoedaOrigem,
      ),
      onPress: () => {
        navigate('InvoiceCardDetails', {
          date: new Date().getTime(),
          referanceId: transaction.NumeroReferencia,
          data: transactionFormatted,
        });
      },
    };

    if (transaction?.Estabelecimento) {
      transactionFormatted.usePoint = { name: transaction?.Estabelecimento };
    }

    if (transaction?.Veiculo && transaction.Veiculo?.Placa) {
      transactionFormatted.item = { plate: transaction.Veiculo?.Placa };
    }

    if (typeof dateIndex !== 'undefined' && dateIndex >= 0) {
      acc[transactionDate].push(transactionFormatted);
      return acc;
    }

    return { ...acc, [transactionDate]: [transactionFormatted] };
  }, {} as InvoiceObj['items']);
};

const getDescriptionTransaction = (transaction: ShortTypes['Compras'][0]) => {
  if (transaction?.Moeda !== 'BRL')
    return `${transaction?.Moeda} ${formatToNumericCurrency(
      transaction.ValorOriginalTransacao,
      getDecimalPlacesBasedOnValue(transaction.ValorOriginalTransacao),
    )}`;
  return transaction.TotalParcelas > 1
    ? `Parcela ${transaction.Parcela}/${transaction.TotalParcelas}`
    : 'À vista';
};

export const getBlockCode = (reducers: AppReducers) => {
  return reducers?.productsReducer?.data?.[0]?.TipoBloqueio;
};

const getUnifiedTransactions: FunctionsType['getUnifiedTransactions'] =
  cards => {
    if (cards?.length === 0) return [];

    const unifiedTransactions = cards.reduce(
      (result: ShortTypes['CartaoCredito'], transaction, index) => {
        const existingIndex = result.findIndex(
          item =>
            getReplacedCreditCard(item.Cartao) ===
            getReplacedCreditCard(transaction.Cartao),
        );
        if (existingIndex !== -1) {
          result[existingIndex].Compras = (
            result[existingIndex].Compras || []
          ).concat(transaction.Compras);
        } else {
          result.push(transaction);
        }
        return result;
      },
      [],
    );

    return unifiedTransactions;
  };

const getReplacedCreditCard = (creditCardNumber: string) => {
  return creditCardNumber?.replace(/X/g, '');
};

const getFilteredUndefinedTypes: (
  transactions: ShortTypes['Compras'],
) => ShortTypes['Compras'] = transactions => {
  return transactions?.filter(
    transaction => transaction?.Tipo?.toLocaleLowerCase() !== 'nd',
  );
};

export const mergeInvoices = (
  semPararPlusInvoicesReducer: InvoicesFintechProps,
  tagInvoices: InvoicesListFintechResponse,
) => {
  const invoices: Record<string, Array<PreviousInvoice>> = {};

  semPararPlusInvoicesReducer?.invoiceMonths?.forEach(monthData => {
    const dueDate = moment(monthData.dueDate.toString());
    const year = dueDate.year();
    const month = dueDate.format('MMMM');
    const day = dueDate.date();
    if (monthData?.situation === 'Em Aberto') return;
    const invoice: PreviousInvoice = {
      month,
      day,
      year,
      isTAG: false,
      invoiceNumber: undefined,
      dueDate: dueDate.toDate(),
    };

    if (typeof invoices[year] !== 'undefined') {
      invoices[year].push(invoice);
      return;
    }
    invoices[year] = [invoice];
  });

  tagInvoices?.billSummaryList.forEach(bill => {
    const invoiceNumber = bill?.billNumberTokenized;
    const billDate = moment(bill?.dueDateOfBill);
    const year = billDate.year();

    const month = billDate.format('MMMM');
    const day = billDate.date();
    const invoice: PreviousInvoice = {
      year,
      month,
      day,
      isTAG: true,
      invoiceNumber,
      dueDate: billDate.toDate(),
    };

    const hasInvoice = invoices?.[year]?.some(
      SPInvoice => SPInvoice.month === month,
    );

    if (!hasInvoice) {
      if (typeof invoices[year] !== 'undefined') {
        invoices[year].push(invoice);
        return;
      }
      invoices[year] = [invoice];
    }
  });

  const sortedInvoices = Object.entries(invoices).reduce(
    (acc, [year, invoice]) => {
      acc[year] = invoice.sort((a, b) => b.dueDate - a.dueDate);
      return acc;
    },
    {} as Record<string, Array<PreviousInvoice>>,
  );
  return sortedInvoices;
};

