    if (callBack) {
      yield call(callBack, { statusCode: response.status });
    }

    yield put(blockCardActions.blockCardSuccess(response.data));
  } catch (error) {
    const { response } = error as AxiosError<BlockCardResponse>;
    const responseData = response?.data;

    yield put(blockCardActions.blockCardFailed(responseData));
  }
}

