export function* getAutoDebtSituation() {
  try {
    const cpf: string = yield select(getCustomerCpf);

    if (!cpf) throw new Error('Insufficient information!');

    const { data }: AxiosResponse<AutomaticDebtResponse> = yield call(
      api.get,
      `/debito-automatico/${cpf}`,
    );

    const isActive = !!(
      data?.data?.bankNumber && data?.data?.checkingAccountNumber
    );

    yield put(automaticDebtActions.automaticDebtSuccess({ ...data, isActive }));
  } catch (error) {
    yield put(automaticDebtActions.automaticDebtClean());
  }
}

import { AxiosError, AxiosResponse } from 'axios';
import { call, put, putResolve, select } from 'redux-saga/effects';

import api from '../../services/api';
import { cardsActions } from '../ducks/customers/cards';
import {
  DuplicateCardResponse,
  duplicateCardActions,
} from '../ducks/duplicateCard';
import { AppReducers } from '../reducers/Models';
import { getCardsReducer } from './_utils/getCardData';

export function* duplicateCardRequest({
  data: {
    lastFourNumbers,
    accountNumber,
    isVirtual,
    organizationNumber,
    onSuccess,
    reasonBlockCode,
    onFailed,
  },
}: {
  data: {
    lastFourNumbers: string;
    accountNumber: string;
    isVirtual: boolean;
    organizationNumber: number;
    type: string;
    reasonBlockCode?: string;
    onSuccess?: () => void;
    onFailed?: () => void;
  };
}) {
  try {
    yield putResolve(cardsActions.cardRequest(() => {}));

    const cardsReducer: AppReducers['cardsReducer'] = yield select(
      getCardsReducer,
    );

    const encryptedCardNumber = cardsReducer.data?.Cards.find(card =>
      card.NrCartao.endsWith(lastFourNumbers),
    )?.CartaoCriptografado;
    if (!encryptedCardNumber) throw new Error('Encrypted Card Not Found!');


    const response: AxiosResponse<DuplicateCardResponse> = yield call(
      api.post,
      `/cards/duplicate-card`,
      {
        encryptedCardNumber,
        accountNumber,
        isVirtual,
        organizationNumber,
        ...(reasonBlockCode && { reasonBlockCode }),
      },
    );
    if (onSuccess) {
      yield call(onSuccess);
    }
    yield put(duplicateCardActions.duplicateCardSuccess(response?.data));
  } catch (error) {
    const { response } = error as AxiosError<DuplicateCardResponse>;
    const responseData = response?.data;
    if (onFailed) {
      yield call(onFailed);
    }
    yield put(duplicateCardActions.duplicateCardFailed(responseData));
  }
}

function* duplicateCardClear() {
  yield call(duplicateCardActions.duplicateCardClear);
}

import { api } from '@semparar/mf-app-user';
import { call, delay, put, race, select } from 'redux-saga/effects';

import { exemptionEligibilityActions } from '../../ducks/exemptionEligibility';
import { AppReducers } from '../../reducers/Models';

const getFeaturesState = (state: AppReducers) => state.featuresReducer;

export function* getExemptionEligibility() {
  try {
    const featuresState: AppReducers['featuresReducer'] = yield select(
      getFeaturesState,
    );

    const hideBenefitMonthlyFeeExemption =
      Reflect.get(featuresState, 'hideBenefitMonthlyFeeExemption') ?? false;

    if (hideBenefitMonthlyFeeExemption) {
      throw new Error('isEligible is not a boolean');
    }

    const { response } = yield race({
      response: call(api.post, '/fintech/v1/fee/checkFeeExemptionEligibility'),
    });

    if (
      Reflect.has(response.data, 'isEligible') &&
      typeof response.data.isEligible === 'boolean'
    ) {
      yield put(
        exemptionEligibilityActions.successExemptionEligibility(response.data),
      );
    } else {
      throw new Error('isEligible is not a boolean');
    }
  } catch (error) {
    yield put(exemptionEligibilityActions.failedExemptionEligibility());
  }
}

