import { AccountTypes, api } from '@semparar/mf-app-user';
import { AxiosResponse } from 'axios';
import { call, select } from 'redux-saga/effects';

const getAccountReducer = ({
  accountReducer,
}: {
  accountReducer: typeof AccountTypes;
}) => accountReducer;

export interface InvoiceDetailsResponseData {
  serviceMessage: {
    codigoRetorno: number;
  };
  data: {
    usePoint: {
      name: string;
    };
    item: {
      plate?: string;
      dateTime?: string;
      name?: string;
      quantity?: string;
      value?: string;
    };
  };
}

export interface InvoiceDetailsRequest {
  callback: (data: {
    response: InvoiceDetailsResponseData | undefined;
    statusCode: number | undefined;
  }) => void;
  id: string;
}

export function* getInvoiceDetails({ id, callback }: InvoiceDetailsRequest) {
  try {
    const { id: accountId } = yield select(getAccountReducer);
    const response: AxiosResponse<InvoiceDetailsResponseData> = yield call(
      api.get,
      `/financial/v1/balance/${accountId}/${id}`,
    );

    yield call(callback, {
      response: response.data,
      statusCode: response.status,
    });
  } catch (err) {
    yield call(callback, {
      response: undefined,
      statusCode: 500,
    });
  }
}

import { propsItems as CardClosedInvoicePropsItems } from '@semparar/design-system-app/src/atomic/fintech/CardClosedInvoice/Models/index';
import { PropsIconsNameCore } from '@semparar/design-system-app/src/styles/Models/type.icon';
import { AccountTypes } from '@semparar/mf-app-user';
import { navigate } from '~/routes/navigation';

import { PreviousInvoice } from '../../../screens/InvoicesHistory/Models';
import { moment } from '../../../services/moment';
import {
  capitalizeEachWord,
  formatToCurrency,
  formatToNumericCurrency,
  removeExtraSpaces,
} from '../../../utils/functions';
import transactionsIds, {
  CAPTURE_TYPE_NUMBER_TYPE,
  TRANSACTIONS_NUMBER_TYPE,
  captureType,
} from '../../../utils/transactions';
import {
  FiservBlockTypes,
  State as ProductsTypes,
} from '../../ducks/customers/products';
import { InvoiceObj } from '../../ducks/invoice';
import {
  InvoicesFintechProps,
  InvoicesFintechResponse,
} from '../../ducks/invoices';
import { InvoicesListFintechResponse } from '../../ducks/invoicesList';
import { AppReducers } from '../../reducers/Models';
import { InvoiceDetailsResponseData } from './details';
import { FunctionsType, ShortTypes, TransactionResume } from './Models/invoice';

export const getAccount = ({
  accountReducer,
}: {
  accountReducer: typeof AccountTypes;
}) => accountReducer;

export const getCards = ({
  productsReducer,
}: {
  productsReducer: ProductsTypes;
}) => productsReducer.data;

export const getSituation = (
  currentInvoice: InvoicesFintechResponse['data']['invoices'][0],
  allInvoices: InvoicesFintechResponse['data']['invoices'],
  blockCode: FiservBlockTypes | undefined,
  currentDate: moment.Moment = moment(),
): CardClosedInvoicePropsItems['type'] => {
  if (currentInvoice.Situacao === 'Fechada') {
    const hasNextClosedInvoice = allInvoices?.find(
      invoice =>
        invoice.Situacao === 'Fechada' &&
        moment(invoice.Vencimento).isAfter(moment(currentInvoice.Vencimento)),
    );

    if (
      blockCode !== FiservBlockTypes.WAITING_PAYMENT &&
      currentInvoice.Pagamento === 'Não Pago' &&
      currentInvoice.ValorPgtoMinimo > currentInvoice.ValorPago &&
      currentInvoice.ValorPago > 0 &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      !hasNextClosedInvoice
    ) {
      return 'late';
    }

    if (
      blockCode !== FiservBlockTypes.WAITING_PAYMENT &&
      currentInvoice.Pagamento === 'Não Pago' &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      !hasNextClosedInvoice
    ) {
      return 'delayed';
    }

    if (
      (blockCode === FiservBlockTypes.WAITING_PAYMENT &&
        currentDate.month() === moment(currentInvoice.Vencimento).month()) ||
      (currentInvoice.Pagamento === 'Não Pago' &&
        !currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')))
    ) {
      return 'closed';
    }

    if (
      currentInvoice.Pagamento === 'Não Pago' &&
      currentDate.isAfter(moment(currentInvoice.Vencimento).add(2, 'days')) &&
      hasNextClosedInvoice
    ) {
      return 'unidentifiedPayment';
    }

    if (
      currentInvoice.Pagamento === 'Pago Integral' &&
      currentInvoice.Valor === currentInvoice.ValorPago
    ) {
      return 'paid';
    }
    if (currentInvoice.status === 'Atrasada') {
      return 'late';
    }

    if (
      currentInvoice.Pagamento === 'Pago Parcial' &&
      currentInvoice.ValorPgtoMinimo <= currentInvoice.ValorPago
    ) {
      return 'paidMessage';
    }

    return 'paid';
  }
  if (currentInvoice.Situacao === 'Em Aberto') {
    return 'default';
  }
