export const mergeInvoices = (
  semPararPlusInvoicesReducer: InvoicesFintechProps,
  tagInvoices: InvoicesListFintechResponse,
) => {
  const invoices: Record<string, Array<PreviousInvoice>> = {};

  semPararPlusInvoicesReducer?.invoiceMonths?.forEach(monthData => {
    const dueDate = moment(monthData.dueDate.toString());
    const year = dueDate.year();
    const month = dueDate.format('MMMM');
    const day = dueDate.date();
    if (monthData?.situation === 'Em Aberto') return;
    const invoice: PreviousInvoice = {
      month,
      day,
      year,
      isTAG: false,
      invoiceNumber: undefined,
      dueDate: dueDate.toDate(),
    };

    if (typeof invoices[year] !== 'undefined') {
      invoices[year].push(invoice);
      return;
    }
    invoices[year] = [invoice];
  });

  tagInvoices?.billSummaryList.forEach(bill => {
    const invoiceNumber = bill?.billNumberTokenized;
    const billDate = moment(bill?.dueDateOfBill);
    const year = billDate.year();

    const month = billDate.format('MMMM');
    const day = billDate.date();
    const invoice: PreviousInvoice = {
      year,
      month,
      day,
      isTAG: true,
      invoiceNumber,
      dueDate: billDate.toDate(),
    };

    const hasInvoice = invoices?.[year]?.some(
      SPInvoice => SPInvoice.month === month,
    );

    if (!hasInvoice) {
      if (typeof invoices[year] !== 'undefined') {
        invoices[year].push(invoice);
        return;
      }
      invoices[year] = [invoice];
    }
  });

  const sortedInvoices = Object.entries(invoices).reduce(
    (acc, [year, invoice]) => {
      acc[year] = invoice.sort((a, b) => b.dueDate - a.dueDate);
      return acc;
    },
    {} as Record<string, Array<PreviousInvoice>>,
  );
  return sortedInvoices;
};

