      dueDate: billDate.toDate(),
    };

    const hasInvoice = invoices?.[year]?.some(
      SPInvoice => SPInvoice.month === month,
    );

    if (!hasInvoice) {
      if (typeof invoices[year] !== 'undefined') {
        invoices[year].push(invoice);
        return;
      }
      invoices[year] = [invoice];
    }
  });

  const sortedInvoices = Object.entries(invoices).reduce(
    (acc, [year, invoice]) => {
      acc[year] = invoice.sort((a, b) => b.dueDate - a.dueDate);
      return acc;
    },
    {} as Record<string, Array<PreviousInvoice>>,
  );
  return sortedInvoices;
};

