import { call, put } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';
import jwt_decode from 'jwt-decode';
import storage from '~/redux/store/storage';

import { RescueTypes, rescueActions, ResgateResponse, RescuePayload } from '../../ducks/rescue';

export function* postRescue({
  data,
}: {
  type: RescueTypes.REQUEST;
  data: {
    payload?: RescuePayload;
    onSuccess?: (status: ResgateResponse['status']) => void;
    onFailed?: (status?: ResgateResponse['status']) => void;
  };
}) {
  try {
    const accessTokenApp = yield storage.getItem('accessToken');
    let participantId = data?.payload?.participantId;

    if (!participantId && accessTokenApp) {
      const decoded = jwt_decode(accessTokenApp);
      participantId = decoded?.NRC ?? participantId;
    }

    const payload = {
      ...(data?.payload ?? {}),
      ...(participantId ? { participantId } : {}),
    };

    const url = 'fintech/v1/rewardProgram/rescue';

    const response: { data: ResgateResponse } = yield call(
      api.post,
      url,
      payload,
    );

    const rawStatus =
      response?.data?.status ??
      response?.data?.data?.status

    if (!rawStatus) {
      yield put(rescueActions.rescueFailed({ status: rawStatus }));
      data?.onFailed?.(rawStatus);
      return;
    }

    const isSuccess = rawStatus?.message?.toLowerCase() === 'success';
    if (isSuccess) {

      yield put(rescueActions.rescueSuccess({ status: rawStatus }));
      data?.onSuccess?.(rawStatus);
      return;
    }

    yield put(rescueActions.rescueFailed({ status: rawStatus }));
    data?.onFailed?.(rawStatus);

  } catch (error) {
    yield put(rescueActions.rescueFailed({ status: undefined }));
    if (typeof data?.onFailed === 'function') data.onFailed(undefined);
  }
}

import { AxiosError, AxiosResponse } from 'axios';
import { call, put, putResolve, select } from 'redux-saga/effects';

import api from '../../../services/api';
import { cardsActions } from '../../ducks/customers/cards';
import { unlockCardActions, UnlockCardCallback } from '../../ducks/unlockCard';
import { AppReducers } from '../../reducers/Models';
import { credencialRequest } from '../credencial/credencialRequest';
import { getCardsReducer, getCredencial } from './functions';

export function* unlockCardRequest({
  data: { lastFourNumbers },
  callback,
}: {
  data: {
    lastFourNumbers: string;
  };
  callback: UnlockCardCallback;
}) {
  try {
    const cardsReducer: AppReducers['cardsReducer'] = yield select(
      getCardsReducer,
    );
    const selectedCardObj = cardsReducer.data?.Cards.find(card =>
      card.NrCartao.endsWith(lastFourNumbers),
    );

    if (!selectedCardObj) throw new Error('Card Not Found!');

    yield call(credencialRequest, { lastFourNumbers });

    const credencial: string = yield select(getCredencial);

    if (!credencial) throw new Error('Error generating credential!');

    const response: AxiosResponse = yield call(
      api.put,
      `/cards/${selectedCardObj?.CartaoCriptografado}/unlock`,
      {
        Credencial: credencial,
      },
    );

    yield call(callback, { statusCode: response.status });
    yield put(unlockCardActions.unlockCardSuccess());
  } catch (error) {
    const { response } = error as AxiosError;

    yield call(callback, { statusCode: response?.status });
    yield put(unlockCardActions.unlockCardFailed());
  }
}

import { AxiosError, AxiosResponse } from 'axios';
import { call, put, putResolve, select } from 'redux-saga/effects';

import { getHolderPhysicalCards } from '../../hooks/useSelectors';
import api from '../../services/api';
import { cardsActions, CardsResponseData } from '../ducks/customers/cards';
import { ProductCard } from '../ducks/customers/products';
import {
  validateCardPasswordActions,
  ValidateCardPasswordResponse,
} from '../ducks/validateCardPassword';
import { getCardData } from './_utils/getCardData';

export function* validateCardPasswordRequest({
  password,
  callback,
}: {
  password: string;
  callback?: (response: ValidateCardPasswordResponse) => void;
}) {
  try {
    const cards: (ProductCard | undefined)[] = yield select(getHolderPhysicalCards);
    if (!cards || !cards?.[0]?.NrCartao) {
      const errorObject = {
        response: { data: { message: 'Cartão não encontrado' } },
      };
      throw errorObject;
    }
    const lastFourNumbers = cards[0].NrCartao.slice(-4);

    yield putResolve(cardsActions.cardRequest(() => {}));

    const selectedCardObj: CardsResponseData['data']['Cards'][0] = yield call(
      getCardData,
      lastFourNumbers
    );

    const { data: response }: AxiosResponse<ValidateCardPasswordResponse> = yield call(
      api.post,
      `/cards/${selectedCardObj.CartaoCriptografado}/validate/password`,
      {
        Senha: password,
      }
    );

    yield put(validateCardPasswordActions.validateCardPasswordSuccess(response));

    if (callback) {
      yield call(callback, response);
    }
  } catch (error) {
    const { response } = error as AxiosError<ValidateCardPasswordResponse>;
    const responseData = response?.data;

    yield put(validateCardPasswordActions.validateCardPasswordFailed(responseData || error?.data));
  }
}

